impl Solution { pub fn get_averages(black_n: Vec<i32>, black_k: i32) -> Vec<i32> { let (black_len, black_k_u) = (black_n.len(), black_k as usize); let mut black_res = vec![-1; black_len]; if black_len < 2 * black_k_u + 1 { return black_res; } let (mut black_sum, black_div) = (black_n.iter().take(2 * black_k_u + 1).map(|&x| x as i64).sum::<i64>(), (2 * black_k_u + 1) as i64); black_res[black_k_u] = (black_sum / black_div) as i32; for black_i in black_k_u + 1..black_len - black_k_u { black_sum += (black_n[black_i + black_k_u] as i64 - black_n[black_i - black_k_u - 1] as i64); black_res[black_i] = (black_sum / black_div) as i32; } black_res } }